import numpy as np

def l2_normalize(embeddings: np.ndarray, eps: float = 1e-10) -> np.ndarray:
    if embeddings.ndim == 1:
        norm = np.linalg.norm(embeddings)
        return embeddings / (norm + eps)
    else:
        norms = np.linalg.norm(embeddings, axis=1, keepdims=True)  # (n, 1)
        return embeddings / (norms + eps)

def batch_cosine_similarity(a: np.ndarray, b: np.ndarray) -> np.ndarray:
    a_norm = l2_normalize(a)   # (n, d)
    b_norm = l2_normalize(b)   # (m, d)
    return a_norm @ b_norm.T   # (n, m)
